class Solution:
    def maxNonDecreasingLength(self, nums1: List[int], nums2: List[int]) -> int:
        n = len(nums1)
        max_len = 1
        dp = [1] * n

        for i in range(1, n):
            if nums1[i] >= nums1[i - 1]:
                dp[i] = dp[i - 1] + 1
            elif nums1[i] >= nums2[i - 1]:
                dp[i] = dp[i - 1] + 1
            elif nums2[i] >= nums1[i - 1]:
                dp[i] = dp[i - 1] + 1
            elif nums2[i] >= nums2[i - 1]:
                dp[i] = dp[i - 1] + 1
            else:
                dp[i] = 1

            max_len = max(max_len, dp[i])

        return max_len
